def _add_artifact_upload_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument("--file", required=True)
    parser.add_argument("--artifact-id")
    parser.add_argument("--artifact-type", default="file")
    parser.add_argument("--title")
    parser.add_argument("--runtime-context-json")
    parser.add_argument("--runtime-context-file")
    parser.add_argument("--metadata-json")
    parser.add_argument("--metadata-file")
    # Markdown customer deliverables are public by default; --no-public keeps them private.
    parser.add_argument(
        "--public",
        action=argparse.BooleanOptionalAction,
        default=True,
        help="Publish markdown artifacts to a public share URL (default: true).",
    )
    parser.add_argument("--dry-run", action="store_true")


def _add_artifact_share_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument("--artifact-id", required=True)
    parser.add_argument("--dry-run", action="store_true")


def _add_artifact_validate_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument("--file", required=True)


def _build_artifact_upload_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _load_structured_args(args)
    payload.update(
        _without_none(
            {
                "file": args.file,
                "artifact_id": args.artifact_id,
                "artifact_type": args.artifact_type,
                "title": args.title,
                "runtime_context": _structured_object_arg(
                    args.runtime_context_json,
                    args.runtime_context_file,
                    flag="--runtime-context-json",
                    file_flag="--runtime-context-file",
                ),
                "metadata": _structured_object_arg(
                    args.metadata_json,
                    args.metadata_file,
                    flag="--metadata-json",
                    file_flag="--metadata-file",
                ),
                "public": bool(args.public),
            }
        )
    )
    return _without_none(payload)


def _build_artifact_share_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _load_structured_args(args)
    payload.update({"artifact_id": args.artifact_id})
    return _without_none(payload)


def _build_artifact_validate_arguments(args: argparse.Namespace) -> dict[str, Any]:
    return {"file": args.file}


def _structured_object_arg(
    value: str | None,
    file_value: str | None,
    *,
    flag: str,
    file_flag: str,
) -> dict[str, Any] | None:
    if value is not None and file_value is not None:
        raise ValueError(f"{flag} and {file_flag} cannot be used together.")
    if value is not None:
        return _json_object(value, flag=flag)
    if file_value is not None:
        raw = Path(file_value).read_text(encoding="utf-8")
        return _json_object(raw, flag=file_flag)
    return None


